{"code": "import itertools

def max_k_tiling(N):
    # backtracking to tile NxN square with rectangles of integer sides,
    # maximize number of rectangles with distinct perimeters.
    # Use recursion on grid.
    grid = [[-1]*N for _ in range(N)]  # -1 free, else rectangle id
    rects = []  # list of (w,h) for each rectangle
    perimeters = set()
    best = 0
    best_rects = None

    # precompute all possible rectangle dimensions (w,h) that can fit in N
    rectangles = [(w,h) for w in range(1,N+1) for h in range(1,N+1)]
    # sort by area maybe? Not needed.

    def backtrack():
        nonlocal best, best_rects
        # find first free cell
        for fy in range(N):
            for fx in range(N):
                if grid[fy][fx] == -1:
                    # try place rectangle of each dimension that fits
                    for w,h in rectangles:
                        if fx+w <= N and fy+h <= N:
                            # check if area free
                            ok = True
                            for dy in range(h):
                                for dx in range(w):
                                    if grid[fy+dy][fx+dx] != -1:
                                        ok = False
                                        break
                                if not ok:
                                    break
                            if not ok:
                                continue
                            # compute perimeter
                            p = 2*(w+h)
                            if p in perimeters:
                                continue
                            # place
                            rect_id = len(rects)
                            rects.append((w,h))
                            perimeters.add(p)
                            for dy in range(h):
                                for dx in range(w):
                                    grid[fy+dy][fx+dx] = rect_id
                            backtrack()
                            # undo
                            for dy in range(h):
                                for dx in range(w):
                                    grid[fy+dy][fx+dx] = -1
                            perimeters.remove(p)
                            rects.pop()
                    return  # after trying all possibilities for this cell, backtrack
        # if no free cell, we have a complete tiling
        if len(rects) > best:
            best = len(rects)
            best_rects = rects.copy()
            # print("found", best, rects)
        # return

    backtrack()
    return best, best_rects

for N in range(1,5):
