def divisors(x):
    divs = []
    for i in range(1, int(x**0.5) + 1):
        if x % i == 0:
            divs.append(i)
            if i != x // i:
                divs.append(x // i)
    return sorted(divs)

def f(n):
    x = 1
    while True:
        divs = divisors(x)
        # Check if any three distinct divisors sum to n
        found = False
        for i in range(len(divs)):
            for j in range(i+1, len(divs)):
                for k in range(j+1, len(divs)):
                    if divs[i] + divs[j] + divs[k] == n:
                        found = True
                        break
                if found:
