def all_orderings_list(m):
    n = 2**m
    speeds = list(range(n, 0, -1))
    from collections import defaultdict
    def round_gen(scores, round_idx):
        groups = defaultdict(list)
        for idx, sc in enumerate(scores):
            groups[sc].append(idx)
        group_items = list(groups.values())
        def gen_matchings(players):
            if len(players) == 0:
                yield []
            else:
                first = players[0]
                for i in range(1, len(players)):
                    second = players[i]
                    rest = players[1:i] + players[i+1:]
                    for sub in gen_matchings(rest):
                        yield [(first, second)] + sub
        def generate_next(matchings_list, idx):
            if idx == len(group_items):
                new_scores = list(scores)
                for (i,j) in matchings_list:
                    if speeds[i] > speeds[j]:
                        win = i
                    else:
                        win = j
                    new_scores[win] += 2**(m - round_idx)
                yield tuple(new_scores)
            else:
                group = group_items[idx]
                for matching in gen_matchings(group):
                    for rest in generate_next(matchings_list + matching, idx+1):
                        yield rest
        yield from generate_next([], 0)

    init_scores = tuple([0]*n)
    final_set = set()
    def dfs(scores, r):
        if r > m:
            final_set.add(scores)
            return
        for ns in round_gen(scores, r):
            dfs(ns, r+1)
    dfs(init_scores, 1)
    orderings = set()
    for sc in final_set:
        order = tuple(sorted(range(n), key=lambda i: sc[i], reverse=True))
        orderings.add(order)
    return orderings, final_set

