    for a in range(1, n-1):
        for b in range(a+1, n-a):
            c = n - a - b
            if c <= b:
                continue
            l = lcm(lcm(a,b), c)
            if best is None or l < best:
                best = l
                best_triple = (a,b,c)
    return best, best_triple

